/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Pedido Venda"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &PedCod.IsEmpty() print printBlockFilterPedCod EndIf If not &PedSts.IsEmpty() &FilterPedStsValueDescription = &PedSts.EnumerationDescription()
print printBlockFilterPedSts EndIf If not &PedCliCod.IsEmpty() print printBlockFilterPedCliCod EndIf If not &PedStsEmb.IsEmpty() &FilterPedStsEmbValueDescription = &PedStsEmb.EnumerationDescription()
print printBlockFilterPedStsEmb EndIf If not &PedTraSaiCod.IsEmpty() print printBlockFilterPedTraSaiCod EndIf If not &PedTraSaiRaz.IsEmpty() print printBlockFilterPedTraSaiRaz EndIf If not &PedNovStsFinNom.IsEmpty() print printBlockFilterPedNovStsFinNom EndIf If not &PedDtaEms.IsEmpty() print printBlockFilterPedDtaEms EndIf If not &PedDtaEms_To.IsEmpty() &PedDtaEms_To_Description = format('%1 (%2)', "Emissão", "até") print printBlockFilterPedDtaEms_To EndIf If not &LctTip.IsEmpty() &FilterLctTipValueDescription = &LctTip.EnumerationDescription()
print printBlockFilterLctTip EndIf If not &LctAtuSal.IsEmpty() &FilterLctAtuSalValueDescription = &LctAtuSal.EnumerationDescription()
print printBlockFilterLctAtuSal EndIf If not &PedBlq.IsEmpty() &FilterPedBlqValueDescription = &PedBlq.EnumerationDescription()
print printBlockFilterPedBlq EndIf If not &FilCod.IsEmpty() print printBlockFilterFilCod EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'LCTCOD' &LctCod1.FromString(&GridStateDynamicFilter.Value) If not &LctCod1.IsEmpty() &LctCod = &LctCod1 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector1 = !'PEDVENCOD' &PedVenCod1.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod1.IsEmpty() &PedVenCod = &PedVenCod1 print printBlockFilterPedVenCod EndIf Case &DynamicFiltersSelector1 = !'PEDDTAEMBA' &PedDtaEmba1.FromString(&GridStateDynamicFilter.Value) &PedDtaEmba_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaEmba1.IsEmpty() &FilterPedDtaEmbaDescription = "Dta.Embalo" &PedDtaEmba = &PedDtaEmba1 print printBlockFilterPedDtaEmba EndIf If not &PedDtaEmba_To1.IsEmpty() &FilterPedDtaEmbaDescription = format('%1 (%2)', "Dta.Embalo", "até") &PedDtaEmba = &PedDtaEmba_To1 print printBlockFilterPedDtaEmba EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'LCTCOD' &LctCod2.FromString(&GridStateDynamicFilter.Value) If not &LctCod2.IsEmpty() &LctCod = &LctCod2 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector2 = !'PEDVENCOD' &PedVenCod2.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod2.IsEmpty() &PedVenCod = &PedVenCod2 print printBlockFilterPedVenCod EndIf Case &DynamicFiltersSelector2 = !'PEDDTAEMBA' &PedDtaEmba2.FromString(&GridStateDynamicFilter.Value) &PedDtaEmba_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaEmba2.IsEmpty() &FilterPedDtaEmbaDescription = "Dta.Embalo" &PedDtaEmba = &PedDtaEmba2 print printBlockFilterPedDtaEmba EndIf If not &PedDtaEmba_To2.IsEmpty() &FilterPedDtaEmbaDescription = format('%1 (%2)', "Dta.Embalo", "até") &PedDtaEmba = &PedDtaEmba_To2 print printBlockFilterPedDtaEmba EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'LCTCOD' &LctCod3.FromString(&GridStateDynamicFilter.Value) If not &LctCod3.IsEmpty() &LctCod = &LctCod3 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector3 = !'PEDVENCOD' &PedVenCod3.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod3.IsEmpty() &PedVenCod = &PedVenCod3 print printBlockFilterPedVenCod EndIf Case &DynamicFiltersSelector3 = !'PEDDTAEMBA' &PedDtaEmba3.FromString(&GridStateDynamicFilter.Value) &PedDtaEmba_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaEmba3.IsEmpty() &FilterPedDtaEmbaDescription = "Dta.Embalo" &PedDtaEmba = &PedDtaEmba3 print printBlockFilterPedDtaEmba EndIf If not &PedDtaEmba_To3.IsEmpty() &FilterPedDtaEmbaDescription = format('%1 (%2)', "Dta.Embalo", "até") &PedDtaEmba = &PedDtaEmba_To3 print printBlockFilterPedDtaEmba EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (PedCod) when &OrderedBy = 1 order EmpCod FilCod PedCod when &OrderedBy = 2 order PedCod when &OrderedBy = 3 AND &OrderedDsc = False order (PedCod) when &OrderedBy = 3 AND &OrderedDsc = True order PedDtaEms when &OrderedBy = 4 AND &OrderedDsc = False order (PedDtaEms) when &OrderedBy = 4 AND &OrderedDsc = True order PedDtaCrd when &OrderedBy = 5 AND &OrderedDsc = False order (PedDtaCrd) when &OrderedBy = 5 AND &OrderedDsc = True
using DSwwPedidoEmbalado(&PedCod, &PedSts, &PedCliCod, &PedStsEmb, &PedTraSaiCod, &PedTraSaiRaz , &PedNovStsFinNom, &PedDtaEms, &PedDtaEms_To, &LctTip, &LctAtuSal, &PedBlq , &FilCod, &DynamicFiltersSelector1, &LctCod1, &PedVenCod1, &PedDtaEmba1, &PedDtaEmba_To1 , &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &LctCod2, &PedVenCod2, &PedDtaEmba2, &PedDtaEmba_To2 , &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &LctCod3, &PedVenCod3, &PedDtaEmba3, &PedDtaEmba_To3) &gridPedCliCodRaz = PedCliCodRaz &NovoStatusFinanceiro = trim(PedNovStsFinNom)
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wwPedidoEmbaladoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wwPedidoEmbaladoGridState")) Else &GridState.FromXml(&Session.Get(!"wwPedidoEmbaladoGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PEDCOD" &PedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTS" &PedSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLICOD" &PedCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTSEMB" &PedStsEmb.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDTRASAICOD" &PedTraSaiCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDTRASAIRAZ" &PedTraSaiRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDNOVSTSFINNOM" &PedNovStsFinNom.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDDTAEMS" &PedDtaEms.FromString(&GridStateFilterValue.Value) &PedDtaEms_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"LCTTIP" &LctTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"LCTATUSAL" &LctAtuSal.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDBLQ" &PedBlq.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
